example.code:
from pathlib import Path
from pydantic import BaseModel

class ScanResult(BaseModel):
    rationale: str
    relevant_paths: list[str]    # paths into a fixed manifest

def scan(manifest: list[Path], goal: str) -> ScanResult:
    # cheap LLM call: see only the manifest, not the contents
    listing = "\n".join(f"- {p}" for p in manifest)
    return haiku.parse(goal=goal, manifest=listing)

def load_and_reason(scan: ScanResult, goal: str) -> str:
    # validate
    valid = [Path(p) for p in scan.relevant_paths if Path(p).exists()]
    contents = {p: p.read_text() for p in valid}
    # strong LLM call: now sees only what was selected
    return sonnet.process(goal=goal, files=contents)

def descend(path: Path, goal: str) -> Path:
    if path.is_file():
        return path
    children = list(path.iterdir())
    pick = llm.pick_dir(children=children, goal=goal)   # ref-only
    return descend(pick, goal)

target = descend(repo_root, goal)
content = target.read_text()
answer = llm.answer(content=content, goal=goal)

content.prompt:
You will be given a MANIFEST of {n} items, each with id, path, and one-line description. Your job is to select at most {k} ids most relevant to: {goal}.

Return STRICT JSON:
{
  "rationale": "one sentence",
  "relevant_ids": [int, ...]
}

Do NOT return content from the items. Only ids.

MANIFEST:
{manifest}

You are at directory: {path}
Children: {children_listing}

Goal: {goal}

Pick the ONE child most likely to contain what we need. Return:
{
  "rationale": "one sentence",
  "next": "<child name>"
}

After the LLM emits refs, run this code-side prompt back to a small model only if validation fails:

The previous response listed refs that don't exist:
{bad_refs}

Available refs are:
{valid_refs}

Pick the closest matches from the valid list, or say "no match" if none apply. Return STRICT JSON:
{ "corrected": [str, ...], "rejected": [str, ...] }
